public void testNanNotEqualToZero() {
    assertXPathValue(context, "$nan != 0", Boolean.TRUE, Boolean.class);
}

public void testNanNotEqualToItself() {
    assertXPathValue(context, "$nan != $nan", Boolean.TRUE, Boolean.class);
}

public void testNormalNumbersEqual() {
    assertXPathValue(context, "5 = 5", Boolean.TRUE, Boolean.class);
    assertXPathValue(context, "5 != 5", Boolean.FALSE, Boolean.class);
}

public void testNormalNumbersNotEqual() {
    assertXPathValue(context, "5 = 6", Boolean.FALSE, Boolean.class);
    assertXPathValue(context, "5 != 6", Boolean.TRUE, Boolean.class);
}
